import { db } from '../config/firebase';
import { collection, getDocs, query, where } from "firebase/firestore";

export async function citysuggester(city_name) {
  const citiesRef = collection(db, 'City');
  const q = query(citiesRef, where('cityName', '>=', city_name), where('cityName', '<=', city_name + '\uf8ff'));
  const querySnapshot = await getDocs(q);

  let suggestedCity = null;
  let minDistance = Number.MAX_SAFE_INTEGER;

  // iterate over cities that start with the given city name
  querySnapshot.forEach((doc) => {
    const cityName = doc.data().cityName;
    const distance = levenshteinDistance(city_name, cityName);

    // if distance is lower than current minDistance, set this as the suggested city
    if (distance < minDistance) {
      suggestedCity = cityName;
      minDistance = distance;
    }
  });

  return suggestedCity;
}

function levenshteinDistance(s, t) {
  // Create empty 2d array
  const d = [];
  for (let i = 0; i <= s.length; i++) {
    d[i] = new Array(t.length + 1);
  }

  // Initialize first row and column
  for (let i = 0; i <= s.length; i++) {
    d[i][0] = i;
  }
  for (let j = 0; j <= t.length; j++) {
    d[0][j] = j;
  }

  // Fill in rest of matrix
  for (let i = 1; i <= s.length; i++) {
    for (let j = 1; j <= t.length; j++) {
      if (s[i - 1] === t[j - 1]) {
        d[i][j] = d[i - 1][j - 1];
      } else {
        d[i][j] = Math.min(
          d[i - 1][j] + 1,  // deletion
          d[i][j - 1] + 1,  // insertion
          d[i - 1][j - 1] + 1,  // substitution
        );
      }
    }
  }

  return d[s.length][t.length];
}
